Queries.Query:
let ip = '{IPAddress}';
let startTime = ago(7d);
SigninLogs
| where TimeGenerated >= startTime
| where IPAddress == ip
| summarize TotalAttempts = count(), UniqueUsers = dcount(UserPrincipalName), FailedAttempts = countif(ResultType != 0), SuccessfulAttempts = countif(ResultType == 0), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated)

let ip = '{IPAddress}';
let startTime = ago(7d);
AADNonInteractiveUserSignInLogs
| where TimeGenerated >= startTime
| where IPAddress == ip
| summarize TokenSignins = count(), Users = make_set(UserPrincipalName)

let ip = '{IPAddress}';
let startTime = ago(7d);
AADServicePrincipalSignInLogs
| where TimeGenerated >= startTime
| where IPAddress == ip
| summarize ServicePrincipals = make_set(ServicePrincipalName), Resources = make_set(ResourceDisplayName), Attempts = count()

let ip = '{IPAddress}';
let startTime = ago(7d);
AADManagedIdentitySignInLogs
| where TimeGenerated >= startTime
| where IPAddress == ip
| summarize Identities = make_set(ServicePrincipalId), Attempts = count()

let ip = '{IPAddress}';
let startTime = ago(7d);
AzureActivity
| where TimeGenerated >= startTime
| where CallerIpAddress == ip
| summarize Operations = make_set(OperationNameValue), OperationCount = count()

let ip = '{IPAddress}';
let startTime = ago(7d);
AuditLogs
| where TimeGenerated >= startTime
| where InitiatedBy.ipAddress == ip
| summarize Operations = make_set(OperationName), Count = count()
